import { Type } from './Type.js';
/** Maps a database SMALLINT column to a JS `number`. */
export class SmallIntType extends Type {
    getColumnType(prop, platform) {
        return platform.getSmallIntTypeDeclarationSQL(prop);
    }
    compareAsType() {
        return 'number';
    }
    ensureComparable() {
        return false;
    }
}
